// Refactored into smaller, focused functions with lower complexity
class OrderProcessor {
private:
    double applyVipDiscount(Order& order, bool hasDiscount, bool isHoliday) {
        if (!hasDiscount) return order.total;

        for (auto& item : order.items) {
            if (item.isSpecial()) {
                item.price *= isHoliday ? 0.5 : 0.8;
            }
        }
        return order.total;
    }

    void processRegularItems(Order& order) {
        for (auto& item : order.items) {
            if (item.needsProcessing()) {
                processItem(item);
            }
        }
    }

    void processItem(Item& item) {
        try {
            item.process();
        } catch (const ProcessingException& e) {
            if (e.isCritical()) {
                throw;
            }
        }
    }

public:
    int processOrder(Order order, bool isVip, bool hasDiscount, bool isHoliday) {
        if (!order.isValid()) return 0;

        if (isVip) {
            if (hasDiscount) {
                return applyVipDiscount(order, hasDiscount, isHoliday);
            } else if (isHoliday) {
                return processHolidayOrder(order);
            }
        } else {
            processRegularItems(order);
        }

        return order.total;
    }
};
